   623→  null_overload_manager_ = createNullOverloadManager();
   624→
   625→  maybeCreateHeapShrinker();
   626→
   627→  for (const auto& bootstrap_extension : bootstrap_.bootstrap_extensions()) {
   628→    auto& factory = Config::Utility::getAndCheckFactory<Configuration::BootstrapExtensionFactory>(
   629→        bootstrap_extension);
   630→    auto config = Config::Utility::translateAnyToFactoryConfig(
   631→        bootstrap_extension.typed_config(), messageValidationContext().staticValidationVisitor(),
   632→        factory);
   633→    bootstrap_extensions_.push_back(
   634→        factory.createBootstrapExtension(*config, serverFactoryContext()));
   635→  }
   636→
   637→  // Register the fatal actions.
   638→  {
   639→    FatalAction::FatalActionPtrList safe_actions;
   640→    FatalAction::FatalActionPtrList unsafe_actions;
   641→    for (const auto& action_config : bootstrap_.fatal_actions()) {
   642→      auto& factory =
   643→          Config::Utility::getAndCheckFactory<Server::Configuration::FatalActionFactory>(
   644→              action_config.config());
   645→      auto action = factory.createFatalActionFromProto(action_config, this);
   646→
   647→      if (action->isAsyncSignalSafe()) {
   648→        safe_actions.push_back(std::move(action));
   649→      } else {
   650→        unsafe_actions.push_back(std::move(action));
   651→      }
   652→    }
   653→    Envoy::FatalErrorHandler::registerFatalActions(
   654→        std::move(safe_actions), std::move(unsafe_actions), api_->threadFactory());
   655→  }
   656→
   657→  if (!bootstrap_.default_socket_interface().empty()) {
   658→    auto& sock_name = bootstrap_.default_socket_interface();
   659→    auto sock = const_cast<Network::SocketInterface*>(Network::socketInterface(sock_name));
   660→    if (sock != nullptr) {
   661→      Network::SocketInterfaceSingleton::clear();
   662→      Network::SocketInterfaceSingleton::initialize(sock);
   663→    }
   664→  }
   665→
   666→  ListenerManagerFactory* listener_manager_factory = nullptr;
   667→  if (bootstrap_.has_listener_manager()) {
   668→    listener_manager_factory = Config::Utility::getAndCheckFactory<ListenerManagerFactory>(
   669→        bootstrap_.listener_manager(), false);
   670→  } else {
   671→    listener_manager_factory = &Config::Utility::getAndCheckFactoryByName<ListenerManagerFactory>(
   672→        Config::ServerExtensionValues::get().DEFAULT_LISTENER);
   673→  }
   674→
   675→  // Workers get created first so they register for thread local updates.
   676→  listener_manager_ = listener_manager_factory->createListenerManager(
   677→      *this, nullptr, worker_factory_, bootstrap_.enable_dispatcher_stats(), quic_stat_names_);
   678→
   679→  // We can now initialize stats for threading.
   680→  stats_store_.initializeThreading(*dispatcher_, thread_local_);
   681→
   682→  // It's now safe to start writing stats from the main thread's dispatcher.
   683→  if (bootstrap_.enable_dispatcher_stats()) {
   684→    dispatcher_->initializeStats(*stats_store_.rootScope(), "server.");
   685→  }
   686→
   687→  // The broad order of initialization from this point on is the following:
   688→  // 1. Statically provisioned configuration (bootstrap) are loaded.
   689→  // 2. Cluster manager is created and all primary clusters (i.e. with endpoint assignments
   690→  //    provisioned statically in bootstrap, discovered through DNS or file based CDS) are
   691→  //    initialized.
   692→  // 3. Various services are initialized and configured using the bootstrap config.
